from __future__ import annotations

from dataclasses import dataclass
from pathlib import Path

from dnsforge.infrastructure.bind.layout import BindLayout
from dnsforge.domain.zone.template_registry import ZoneTemplateRegistry


@dataclass(frozen=True)
class TemplateArtifact:
    """Logical BIND artifact generated by DNSForge from a registered template."""

    key: str
    template: Path
    redhat_path: Path
    mode: int = 0o640

    def destination(self, layout: BindLayout) -> Path:
        from dnsforge.infrastructure.bind.rendering.template_service import TemplateService

        return TemplateService(layout=layout).destination_for(self.redhat_path)


class TemplateRegistry:
    """Central registry of BIND templates used by the hybrid renderer.

    Every .j2/.tpl file under infrastructure/bind/resources must be referenced
    here. This prevents orphan templates while keeping the modular BIND layout
    readable and distribution-aware.
    """

    ARTIFACTS: tuple[TemplateArtifact, ...] = (
        TemplateArtifact("named.conf", Path("named.conf.j2"), Path("/etc/named.conf")),
        TemplateArtifact("acl", Path("00-acl.conf.j2"), Path("/etc/named/conf.d/00-acl.conf")),
        TemplateArtifact("keys", Path("10-keys.conf.j2"), Path("/etc/named/conf.d/10-keys.conf")),
        TemplateArtifact("options", Path("20-options.conf.j2"), Path("/etc/named/conf.d/20-options.conf")),
        TemplateArtifact("logging", Path("30-logging.conf.j2"), Path("/etc/named/conf.d/30-logging.conf")),
        TemplateArtifact("controls", Path("40-controls.conf.j2"), Path("/etc/named/conf.d/40-controls.conf")),
        TemplateArtifact("statistics", Path("45-statistics.conf.j2"), Path("/etc/named/conf.d/45-statistics.conf")),
        TemplateArtifact("rpz", Path("50-rpz.conf.j2"), Path("/etc/named/conf.d/50-rpz.conf")),
        TemplateArtifact("catalog-conf", Path("55-catalog.conf.j2"), Path("/etc/named/conf.d/55-catalog.conf")),
        TemplateArtifact("views", Path("60-views.conf.j2"), Path("/etc/named/conf.d/60-views.conf")),
        TemplateArtifact("rndc-key", Path("10-keys.conf.j2"), Path("/etc/named/tsig/rndc.key")),
        TemplateArtifact("catalog-zone", Path("catalog.zone.j2"), Path("/etc/named/catalog/catalog.zone")),
        TemplateArtifact(
            "internal-zone-index",
            Path("60-views.conf.j2"),
            Path("/etc/named/views/internal/zones.enabled/zones.index.conf"),
        ),
        TemplateArtifact(
            "external-zone-index",
            Path("60-views.conf.j2"),
            Path("/etc/named/views/external/zones.enabled/zones.index.conf"),
        ),
        TemplateArtifact("rpz-zone", Path("rpz.local.zone.j2"), Path("/var/named/rpz/rpz.local.zone")),
        *tuple(
            TemplateArtifact(
                key=f"zone-template:{artifact.key.profile.value}:{artifact.key.scope.value}:{artifact.key.zone_type.value}",
                template=artifact.template,
                redhat_path=Path("/etc/named/views")
                / artifact.key.scope.value
                / "templates"
                / artifact.destination_name,
            )
            for artifact in ZoneTemplateRegistry.artifacts()
        ),
    )

    @classmethod
    def keys(cls) -> tuple[str, ...]:
        return tuple(artifact.key for artifact in cls.ARTIFACTS)

    @classmethod
    def templates(cls) -> tuple[Path, ...]:
        return tuple(dict.fromkeys(artifact.template for artifact in cls.ARTIFACTS))

    @classmethod
    def destinations(cls, layout: BindLayout) -> tuple[Path, ...]:
        return tuple(artifact.destination(layout) for artifact in cls.ARTIFACTS)

    @classmethod
    def by_key(cls, key: str) -> TemplateArtifact:
        for artifact in cls.ARTIFACTS:
            if artifact.key == key:
                return artifact
        raise KeyError(key)
